import{_ as s,o as i,c as a,ag as t}from"./chunks/framework.CMYkYJvz.js";const c=JSON.parse('{"title":"Breakpoint 使用手册","description":"从 docs/breakpoint.md 自动同步生成的 Breakpoint 使用手册 文档。","frontmatter":{"title":"Breakpoint 使用手册","description":"从 docs/breakpoint.md 自动同步生成的 Breakpoint 使用手册 文档。","editLink":false},"headers":[],"relativePath":"reference/breakpoint.md","filePath":"reference/breakpoint.md"}'),n={name:"reference/breakpoint.md"};function o(p,e,l,r,h,d){return i(),a("div",null,[...e[0]||(e[0]=[t(`<blockquote><p>此页面由 <code>docs/breakpoint.md</code> 自动同步生成。</p></blockquote><h1 id="breakpoint-使用手册" tabindex="-1">Breakpoint 使用手册 <a class="header-anchor" href="#breakpoint-使用手册" aria-label="Permalink to &quot;Breakpoint 使用手册&quot;">​</a></h1><p>Breakpoint 用于在 Bifrost 转发 HTTP 流量时暂停指定 request 或 response。暂停后可以查看并修改 headers/body，再继续放行。它适合临时调试接口、验证上游入参、模拟下游响应、排查鉴权/header 问题，或在不改业务代码的情况下验证请求和响应改写效果。</p><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><ul><li>查看某个接口真正发往上游的 request headers/body。</li><li>临时修改 request body、query、headers 后再发送给上游。</li><li>在 response 返回客户端前修改 headers/body，验证客户端兼容性。</li><li>模拟异常响应、特殊 header 或边界数据。</li><li>只针对某个域名、端口或路径调试，避免影响其他网络请求。</li></ul><p>不建议把 Breakpoint 长期开在宽泛规则上。Breakpoint 是交互式调试能力，命中的流量会等待用户 Resume 或等待超时自动放行；规则越宽，越容易造成请求等待、连接堆积和额外 CPU/内存开销。</p><h2 id="工作方式" tabindex="-1">工作方式 <a class="header-anchor" href="#工作方式" aria-label="Permalink to &quot;工作方式&quot;">​</a></h2><p>Breakpoint 有双重门禁：</p><ol><li>Traffic Toolbar 中的 Breakpoint 开关必须打开。</li><li>请求必须命中包含 <code>breakpoint://request</code> 或 <code>breakpoint://response</code> 的规则。</li></ol><p>只打开 Toolbar 开关不会暂停任何流量。只有全局开关打开，并且规则明确授权了 request 或 response 阶段，流量才会暂停。</p><h2 id="在-webui-中使用" tabindex="-1">在 WebUI 中使用 <a class="header-anchor" href="#在-webui-中使用" aria-label="Permalink to &quot;在 WebUI 中使用&quot;">​</a></h2><ol><li>打开 WebUI，进入 Traffic 页面。</li><li>在 Toolbar 中打开 <code>Breakpoint</code> 开关。</li><li>进入 Rules 页面，为目标流量增加一条尽量精确的规则。</li><li>发送命中该规则的请求。</li><li>回到 Traffic 页面，打开对应请求的 TrafficDetail。</li><li>在暂停面板中查看或修改 headers/body。</li><li>点击 <code>Resume</code> 继续 request 或 response。</li></ol><p>Breakpoint 关闭后，新流量不会再暂停；已经 pending 的 breakpoint 会被释放。</p><h2 id="规则配置" tabindex="-1">规则配置 <a class="header-anchor" href="#规则配置" aria-label="Permalink to &quot;规则配置&quot;">​</a></h2><p>使用 <code>breakpoint</code> 协议选择暂停阶段：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>api.example.com/v1/users breakpoint://request</span></span>
<span class="line"><span>api.example.com/v1/users breakpoint://response</span></span>
<span class="line"><span>api.example.com/v1/users breakpoint://request,response</span></span></code></pre></div><p>支持的 value：</p><ul><li><code>request</code> 或 <code>req</code>：在 request 发往上游前暂停。</li><li><code>response</code> 或 <code>res</code>：在 response 返回客户端前暂停。</li><li><code>request,response</code>、<code>req,res</code>、<code>both</code> 或 <code>all</code>：request 和 response 两个阶段都会暂停。</li></ul><p>建议把规则 pattern 收窄到明确域名、端口、路径或方法。例如只调试登录接口时，优先写登录路径，不要写整个域名。空 value 或无法识别的 value 不会触发 Breakpoint。</p><h2 id="request-breakpoint" tabindex="-1">Request Breakpoint <a class="header-anchor" href="#request-breakpoint" aria-label="Permalink to &quot;Request Breakpoint&quot;">​</a></h2><p><code>breakpoint://request</code> 会在请求发往上游前暂停。适合：</p><ul><li>检查真实 request headers/body。</li><li>临时添加、删除或修改请求 header。</li><li>修改 body 后再发送给上游。</li><li>验证客户端请求是否符合预期。</li></ul><p>Resume 后，上游会收到修改后的 request。若 body 因过大、非文本或流式内容无法编辑，页面会提示 body 被省略，此时只能修改 headers，Resume 时不会替换原始 body。</p><h2 id="response-breakpoint" tabindex="-1">Response Breakpoint <a class="header-anchor" href="#response-breakpoint" aria-label="Permalink to &quot;Response Breakpoint&quot;">​</a></h2><p><code>breakpoint://response</code> 会在上游返回后、客户端收到前暂停。适合：</p><ul><li>查看上游真实响应。</li><li>临时修改响应 header。</li><li>修改响应 body，验证客户端展示或错误处理。</li><li>模拟特殊状态或特殊响应内容。</li></ul><p>Resume 后，客户端会收到修改后的 response。对未知长度的流式响应或过大的 body，Bifrost 会尽量保持原始 streaming 行为，避免为了调试而完整缓存大响应。</p><h2 id="timeout-配置" tabindex="-1">Timeout 配置 <a class="header-anchor" href="#timeout-配置" aria-label="Permalink to &quot;Timeout 配置&quot;">​</a></h2><p>Breakpoint Auto-Resume Timeout 位于 <code>Settings -&gt; Performance</code>。</p><ul><li>默认值：30 秒。</li><li>可配置范围：5 秒到 5 分钟。</li><li>超时后：Bifrost 自动继续原始 request/response，不应用未提交的编辑。</li></ul><p>这个配置用于避免用户忘记点击 Resume 时请求无限等待。较低值能降低网络延迟和连接堆积风险；较高值适合需要较长时间手动检查 headers/body 的场景。超过 5 分钟会带来明显的连接占用和性能风险，因此不允许配置。</p><h2 id="性能与安全建议" tabindex="-1">性能与安全建议 <a class="header-anchor" href="#性能与安全建议" aria-label="Permalink to &quot;性能与安全建议&quot;">​</a></h2><ul><li>默认保持 Breakpoint 关闭，只在需要调试时打开。</li><li>使用精确规则，避免把整个域名或所有流量都纳入 breakpoint。</li><li>优先只暂停需要的阶段：只看请求就用 <code>breakpoint://request</code>，只看响应就用 <code>breakpoint://response</code>。</li><li>调试完成后关闭 Breakpoint 或禁用对应规则。</li><li>对大 body、二进制 body、未知长度 streaming body，Bifrost 会限制编辑能力，避免额外复制和缓存造成明显性能开销。</li><li>如果发现请求等待变长，降低 Auto-Resume Timeout 或收窄规则范围。</li></ul><h2 id="api-自动化" tabindex="-1">API 自动化 <a class="header-anchor" href="#api-自动化" aria-label="Permalink to &quot;API 自动化&quot;">​</a></h2><p>日常使用建议通过 WebUI 操作。需要和外部工具、脚本或团队自动化集成时，可以使用 Admin API。</p><p>启用或关闭全局 Breakpoint 门禁：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sS</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> POST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8800/_bifrost/api/breakpoint/settings</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Content-Type: application/json&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --data</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;enabled&quot;:true,&quot;max_body_bytes&quot;:1048576}&#39;</span></span></code></pre></div><p>修改 Auto-Resume Timeout：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sS</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PUT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8800/_bifrost/api/config/performance</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Content-Type: application/json&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --data</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;breakpoint_timeout_ms&quot;:30000}&#39;</span></span></code></pre></div><p>恢复一个暂停项：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sS</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> POST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8800/_bifrost/api/breakpoint/resume</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Content-Type: application/json&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --data</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;request_id&quot;: &quot;REQ-xxxx&quot;,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;phase&quot;: &quot;request&quot;,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;headers&quot;: [[&quot;X-Debug&quot;, &quot;1&quot;]],</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;body&quot;: &quot;edited body&quot;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  }&#39;</span></span></code></pre></div><p>完整 API 描述可在 WebUI 的 Swagger 页面查看，或通过 <code>/_bifrost/api/openapi.json</code> 获取。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>打开 Breakpoint 后为什么没有暂停？</strong></p><p>确认目标流量命中了包含 <code>breakpoint://request</code> 或 <code>breakpoint://response</code> 的规则。Toolbar 开关只是全局门禁，不会单独暂停流量。</p><p><strong>为什么 body 不能编辑？</strong></p><p>通常是 body 超过上限、不是 UTF-8 文本、属于二进制内容，或是未知长度 streaming body。此时 Bifrost 会保护性能，只允许 header-only pause 或直接保持 streaming。</p><p><strong>请求一直等待怎么办？</strong></p><p>点击 Resume，或等待 Auto-Resume Timeout 自动放行。也可以在 Settings -&gt; Performance 降低 timeout，并收窄 breakpoint 规则范围。</p><p><strong>如何避免影响其他应用？</strong></p><p>使用更精确的规则，例如域名 + 路径 + 方法；调试结束后关闭 Breakpoint 或禁用规则。</p>`,51)])])}const u=s(n,[["render",o]]);export{c as __pageData,u as default};
